const email = $json;

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return '';
}

const from = pick(email.from?.text, email.from, email.sender, email.headers?.from);
const to = pick(email.to?.text, email.to, email.headers?.to);
const subject = pick(email.subject, '(sem assunto)');
const date = pick(email.date, new Date().toISOString());
const text = pick(email.textPlain, email.text, email.body, email.textHtml, email.html, '');

const prompt = `
Você é a Secretária IA do Matheus, consultor de sistemas/TOTVS/SimpleIT.

Analise o e-mail abaixo e devolva em português do Brasil, em formato objetivo.

Regras:
- Classifique prioridade: ALTA, MÉDIA ou BAIXA.
- Identifique cliente/projeto se possível.
- Resuma em até 5 linhas.
- Liste pendências práticas.
- Sugira uma resposta curta e educada.
- Se parecer cobrança, suporte urgente, erro de sistema, reunião ou proposta comercial, destaque.

E-MAIL:
De: ${from}
Para: ${to}
Data: ${date}
Assunto: ${subject}

Conteúdo:
${text}
`;

return [{
  json: {
    from,
    to,
    subject,
    date,
    text,
    prompt
  }
}];

